public async Task HandleExceptionAsync_SetCorrectStatusCode(Type exceptionType, HttpStatusCode expectedStatusCode)

public async Task HandleExceptionAsync_SetCorrectStatusCode(Type exceptionType, HttpStatusCode expectedStatusCode)
{
    // Arrange
